SELECT ip_address
FROM hacking_sessions
WHERE servers_corrupted > 5;

SELECT session_id, session_start_time
FROM hacking_sessions
ORDER BY session_start_time DESC;

SELECT session_id, SUM(bytes_transferred) AS total_bytes_transferred
FROM hacking_sessions
GROUP BY session_id;

SELECT COUNT(*) AS active_users
FROM users
WHERE julianday('now') - julianday(last_login) <= 7;

SELECT hack_id, COUNT(*) AS number_of_sessions
FROM hacking_sessions
GROUP BY hack_id;

SELECT hs.*, h.*, l.*
FROM hacking_sessions hs
JOIN hacks h ON hs.hack_id = h.hack_id
JOIN locations l ON hs.location_id = l.location_id
WHERE h.severity = (
    SELECT MAX(severity) FROM hacks
) AND hs.servers_corrupted + hs.pages_corrupted = (
    SELECT MAX(servers_corrupted + pages_corrupted) FROM hacking_sessions
);

SELECT company_name, contact_email
FROM client_companies
WHERE subscription_type = '2';

SELECT session_start_time, session_duration, servers_corrupted 
FROM hacking_sessions 
ORDER BY session_start_time DESC;
